import 'package:flutter/material.dart';\nimport 'package:qr_flutter/qr_flutter.dart';\nimport 'customer_home.dart';\n\nclass CustomerCardDetail extends StatelessWidget {\n  final LoyaltyCard card;\n\n  const CustomerCardDetail({super.key, required this.card});\n\n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      appBar: AppBar(\n        title: Text(card.businessName),\n      ),\n      body: SingleChildScrollView(\n        child: Column(\n          children: [\n            // Card Visual\n            Container(\n              margin: const EdgeInsets.all(16),\n              decoration: BoxDecoration(\n                gradient: LinearGradient(\n                  begin: Alignment.topLeft,\n                  end: Alignment.bottomRight,\n                  colors: [\n                    card.brandColor,\n                    card.brandColor.withOpacity(0.7),\n                  ],\n                ),\n                borderRadius: BorderRadius.circular(20),\n                boxShadow: [\n                  BoxShadow(\n                    color: card.brandColor.withOpacity(0.3),\n                    blurRadius: 20,\n                    offset: const Offset(0, 10),\n                  ),\n                ],\n              ),\n              child: Padding(\n                padding: const EdgeInsets.all(24),\n                child: Column(\n                  crossAxisAlignment: CrossAxisAlignment.start,\n                  children: [\n                    Row(\n                      children: [\n                        const Icon(Icons.store, color: Colors.white, size: 32),\n                        const SizedBox(width: 12),\n                        Expanded(\n                          child: Text(\n                            card.businessName,\n                            style: const TextStyle(\n                              color: Colors.white,\n                              fontSize: 24,\n                              fontWeight: FontWeight.bold,\n                            ),\n                          ),\n                        ),\n                      ],\n                    ),\n                    const SizedBox(height: 24),\n                    \n                    // Stamp Progress\n                    Container(\n                      padding: const EdgeInsets.all(20),\n                      decoration: BoxDecoration(\n                        color: Colors.white.withOpacity(0.2),\n                        borderRadius: BorderRadius.circular(12),\n                      ),\n                      child: Column(\n                        children: [\n                          Text(\n                            card.isComplete\n                                ? '🎉 Reward Ready!'\n                                : '${card.stampsRemaining} more to go',\n                            style: const TextStyle(\n                              color: Colors.white,\n                              fontSize: 18,\n                              fontWeight: FontWeight.w600,\n                            ),\n                          ),\n                          const SizedBox(height: 16),\n                          _buildStampGrid(),\n                          const SizedBox(height: 16),\n                          Text(\n                            '${card.stampsCollected} / ${card.stampsRequired}',\n                            style: const TextStyle(\n                              color: Colors.white,\n                              fontSize: 32,\n                              fontWeight: FontWeight.bold,\n                            ),\n                          ),\n                        ],\n                      ),\n                    ),\n                  ],\n                ),\n              ),\n            ),\n\n            // Actions\n            Padding(\n              padding: const EdgeInsets.all(16),\n              child: Column(\n                crossAxisAlignment: CrossAxisAlignment.stretch,\n                children: [\n                  if (card.isComplete)\n                    FilledButton.icon(\n                      onPressed: () => _showRedeemQR(context),\n                      icon: const Icon(Icons.card_giftcard),\n                      label: const Padding(\n                        padding: EdgeInsets.all(12),\n                        child: Text('Show QR to Redeem'),\n                      ),\n                      style: FilledButton.styleFrom(\n                        backgroundColor: Colors.purple,\n                      ),\n                    )\n                  else\n                    FilledButton.icon(\n                      onPressed: () => _showStampQR(context),\n                      icon: const Icon(Icons.qr_code),\n                      label: const Padding(\n                        padding: EdgeInsets.all(12),\n                        child: Text('Show QR to Get Stamp'),\n                      ),\n                    ),\n                  const SizedBox(height: 12),\n                  OutlinedButton.icon(\n                    onPressed: () => _showHistory(context),\n                    icon: const Icon(Icons.history),\n                    label: const Text('Transaction History'),\n                  ),\n                ],\n              ),\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  Widget _buildStampGrid() {\n    return Wrap(\n      spacing: 12,\n      runSpacing: 12,\n      alignment: WrapAlignment.center,\n      children: List.generate(card.stampsRequired, (index) {\n        final isCollected = index < card.stampsCollected;\n        return Container(\n          width: 40,\n          height: 40,\n          decoration: BoxDecoration(\n            color: isCollected ? Colors.white : Colors.white.withOpacity(0.2),\n            shape: BoxShape.circle,\n            border: Border.all(\n              color: Colors.white,\n              width: 2,\n            ),\n          ),\n          child: isCollected\n              ? Icon(Icons.check, color: card.brandColor, size: 24)\n              : Center(\n                  child: Text(\n                    '${index + 1}',\n                    style: const TextStyle(\n                      color: Colors.white70,\n                      fontWeight: FontWeight.bold,\n                    ),\n                  ),\n                ),\n        );\n      }),\n    );\n  }\n\n  void _showStampQR(BuildContext context) {\n    final qrData = 'LOYALTYCARD:SHOW:${card.id}:${card.stampsCollected}';\n    \n    showModalBottomSheet(\n      context: context,\n      isScrollControlled: true,\n      builder: (context) => Container(\n        padding: const EdgeInsets.all(32),\n        child: Column(\n          mainAxisSize: MainAxisSize.min,\n          children: [\n            const Icon(\n              Icons.qr_code_scanner,\n              size: 48,\n              color: Colors.blue,\n            ),\n            const SizedBox(height: 16),\n            const Text(\n              'Get Your Stamp',\n              style: TextStyle(\n                fontSize: 24,\n                fontWeight: FontWeight.bold,\n              ),\n            ),\n            const SizedBox(height: 8),\n            Text(\n              'Show this QR code to ${card.businessName} staff',\n              textAlign: TextAlign.center,\n              style: TextStyle(color: Colors.grey[600]),\n            ),\n            const SizedBox(height: 24),\n            QrImageView(\n              data: qrData,\n              version: QrVersions.auto,\n              size: 250.0,\n              backgroundColor: Colors.white,\n            ),\n            const SizedBox(height: 16),\n            Text(\n              'Card ID: ${card.id.substring(0, 8).toUpperCase()}',\n              style: TextStyle(\n                fontSize: 12,\n                color: Colors.grey[500],\n                fontFamily: 'monospace',\n              ),\n            ),\n            const SizedBox(height: 24),\n            OutlinedButton(\n              onPressed: () => Navigator.pop(context),\n              child: const Text('Close'),\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  void _showRedeemQR(BuildContext context) {\n    final qrData = 'LOYALTYCARD:REDEEM:${card.id}:${card.stampsCollected}';\n    \n    showModalBottomSheet(\n      context: context,\n      isScrollControlled: true,\n      builder: (context) => Container(\n        padding: const EdgeInsets.all(32),\n        decoration: BoxDecoration(\n          gradient: LinearGradient(\n            begin: Alignment.topCenter,\n            end: Alignment.bottomCenter,\n            colors: [\n              Colors.purple[50]!,\n              Colors.white,\n            ],\n          ),\n        ),\n        child: Column(\n          mainAxisSize: MainAxisSize.min,\n          children: [\n            const Icon(\n              Icons.celebration,\n              size: 48,\n              color: Colors.purple,\n            ),\n            const SizedBox(height: 16),\n            const Text(\n              'Redeem Your Reward!',\n              style: TextStyle(\n                fontSize: 24,\n                fontWeight: FontWeight.bold,\n              ),\n            ),\n            const SizedBox(height: 8),\n            Text(\n              'Show this QR code to ${card.businessName} to claim your free item',\n              textAlign: TextAlign.center,\n              style: TextStyle(color: Colors.grey[600]),\n            ),\n            const SizedBox(height: 24),\n            Container(\n              padding: const EdgeInsets.all(16),\n              decoration: BoxDecoration(\n                color: Colors.white,\n                borderRadius: BorderRadius.circular(12),\n                boxShadow: [\n                  BoxShadow(\n                    color: Colors.purple.withOpacity(0.1),\n                    blurRadius: 20,\n                  ),\n                ],\n              ),\n              child: QrImageView(\n                data: qrData,\n                version: QrVersions.auto,\n                size: 250.0,\n                backgroundColor: Colors.white,\n              ),\n            ),\n            const SizedBox(height: 16),\n            Container(\n              padding: const EdgeInsets.all(12),\n              decoration: BoxDecoration(\n                color: Colors.green[50],\n                borderRadius: BorderRadius.circular(8),\n              ),\n              child: Row(\n                mainAxisSize: MainAxisSize.min,\n                children: [\n                  const Icon(Icons.check_circle, color: Colors.green),\n                  const SizedBox(width: 8),\n                  Text(\n                    '${card.stampsRequired} stamps completed',\n                    style: const TextStyle(\n                      fontWeight: FontWeight.w600,\n                    ),\n                  ),\n                ],\n              ),\n            ),\n            const SizedBox(height: 24),\n            OutlinedButton(\n              onPressed: () => Navigator.pop(context),\n              child: const Text('Close'),\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  void _showHistory(BuildContext context) {\n    showDialog(\n      context: context,\n      builder: (context) => AlertDialog(\n        title: const Text('Transaction History'),\n        content: Column(\n          mainAxisSize: MainAxisSize.min,\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            _HistoryItem('Stamp Added', 'Today at 2:30 PM'),\n            _HistoryItem('Stamp Added', 'Yesterday at 10:15 AM'),\n            _HistoryItem('Stamp Added', '2 days ago'),\n            _HistoryItem('Card Issued', '5 days ago'),\n          ],\n        ),\n        actions: [\n          TextButton(\n            onPressed: () => Navigator.pop(context),\n            child: const Text('Close'),\n          ),\n        ],\n      ),\n    );\n  }\n}\n\nclass _HistoryItem extends StatelessWidget {\n  final String action;\n  final String time;\n\n  const _HistoryItem(this.action, this.time);\n\n  @override\n  Widget build(BuildContext context) {\n    return Padding(\n      padding: const EdgeInsets.symmetric(vertical: 8),\n      child: Row(\n        children: [\n          const Icon(Icons.circle, size: 8, color: Colors.blue),\n          const SizedBox(width: 12),\n          Expanded(\n            child: Column(\n              crossAxisAlignment: CrossAxisAlignment.start,\n              children: [\n                Text(\n                  action,\n                  style: const TextStyle(fontWeight: FontWeight.w500),\n                ),\n                Text(\n                  time,\n                  style: TextStyle(\n                    fontSize: 12,\n                    color: Colors.grey[600],\n                  ),\n                ),\n              ],\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n}
